class Solution:
    def maxNonDecreasingLength(self, nums1: List[int], nums2: List[int]) -> int:
        if len(nums1) != len(nums2):
            raise ValueError("Input arrays must be the same length")

        res, prev, i = 1, float('inf'), 0
        while i < len(nums1):
            if nums1[i] >= prev:
                res = max(res, 1 + (nums1[i] >= nums2[i]))
            else:
                res = max(res, 1)
            prev = min(nums1[i], nums2[i])
            i += 1

