class Solution:
    def minExtraChar(self, s: str, dictionary: List[str]) -> int:
        # Build a Trie node class
        class TrieNode:
            def __init__(self):
                self.children = {}
                self.end_of_word = False
            def add_word(self, word):
                node = self
                for ch in word:
                    if ch not in node.children:
                        node.children[ch] = TrieNode()
                    node = node.children[ch]
                node.end_of_word = True

        # Build a Trie from the dictionary
        root = TrieNode()
        for word in dictionary:
            root.add_word(word)

        # Initialize the minimum extra character count
        min_extra = float('inf')

        # Define a recursive function to explore possible splits
        def explore(i, node, extra):
            nonlocal min_extra
            # If we've reached the end of the string, update min_extra if necessary
            if i == len(s):
                min_extra = min(min_extra, extra)
                return
            # Otherwise, explore each possible split
            for j in range(i + 1, len(s) + 1):
                substr = s[i:j]
                if substr in root.children:
                    explore(j, root.children[substr], extra + (s[j:i] != ''))
                else:
                    break

        # Start exploring from the root of the Trie
        explore(0, root, 0)

        return min_extra
