def maxSumMinProduct(nums1, nums2):
    m, n = len(nums1), len(nums2)
    dp1, dp2 = [[inf]*n for _ in range(m)], [[inf]*m for _ in range(n)]

    for i in range(m):
        for j in range(n):
            if i == 0 or j == 0:
                dp1[i][j] = dp2[i][j] = min(i, j) * nums1[i] * nums2[j]
            elif nums1[i] == nums2[j]:
                dp1[i][j] = dp2[i][j] = dp1[i-1][j-1] + min(i, j) * nums1[i] * nums2[j]
            elif nums1[i] < nums2[j]:
                dp1[i][j] = max(dp1[i-1][j], dp2[i-1][j] + min(i, j) * nums1[i] * nums2[j])
            else:
                dp2[i][j] = max(dp1[i][j-1], dp2[i-1][j-1] + min(i, j) * nums1[i] * nums2[j])

    return max(dp1[m-1][n-1], dp2[m-1][n-1])
