def min_leftover(s, dictionary):
    """
    This function splits the string `s` into parts found in the `dictionary` without overlaps.

    It uses dynamic programming to find the minimum number of leftover characters.

    Parameters:
    s (str): The input string to be split.
    dictionary (set): A set of words that can be found in the string `s`.

    Returns:
    int: The minimum number of leftover characters.
    """

    memo = {}

    def dfs(i, word):
        if i >= len(s):
            return 0 if word else 1

        if (i, word) in memo:
            return memo[(i, word)]

        include = 0
        if word in dictionary and i + len(word) <= len(s) and s[i:i + len(word)] == word:
            include = 1 + dfs(i + len(word), word)

        exclude = dfs(i + 1, word)

        memo[(i, word)] = min(include, exclude)

        return memo[(i, word)]

    return dfs(0, "")

