    def maxNonDecreasingLength(self, nums1: List[int], nums2: List[int]) -> int:
        m, n = len(nums1), len(nums2)

        # Initialize a dynamic programming table to store the length of the longest non-decreasing subarray ending at each position
        dp1 = [[0] * (n + 1) for _ in range(m + 1)]
        dp2 = [[0] * (n + 1) for _ in range(m + 1)]

        # Initialize the maximum length of the non-decreasing subarray
        max_length = 0

        # Fill up the dynamic programming table for the first row and column
        for i in range(m + 1):
            if i == 0:
                dp1[i][0] = dp2[i][0] = 1
            else:
                for j in range(n + 1):
                    num1, num2 = nums1[i - 1], nums2[j - 1]
                    if j == 0:
                        dp1[i][j] = max(dp1[i - 1][j], 1 if num1 >= dp1[i - 1][j] else 0)
                        dp2[i][j] = max(dp2[i - 1][j], 1 if num2 >= dp2[i - 1][j] else 0)
                    else:
                        dp1[i][j] = max(dp1[i - 1][j], 1 if num1 >= dp1[i - 1][j] else 0, dp1[i][j - 1] if num1 <= min(dp1[i - 1][j - 1], dp1[i][j - 1]) else 0)
